@Keep
class WebBridge(
    private val activity: Activity,
    private val webView: WebView,
    private val localStore: LocalStore,
    private val permissionRequester: (requestId: String, permissions: List<String>) -> Unit,
    private val cameraStarter: (requestId: String) -> Unit,
    private val pushPermissionRequester: (requestId: String) -> Unit
) {
    private val mainHandler = Handler(Looper.getMainLooper())

    @JavascriptInterface
    fun ping(payloadJson: String?): String {
        val res = JSONObject()
        res.put("ok", true)
        res.put("echo", payloadJson ?: "")
        return res.toString()
    }

    @JavascriptInterface
    fun requestPermissions(payloadJson: String) {
        val obj = parseJson(payloadJson) ?: return
        val id = obj.optString("id", UUID.randomUUID().toString())
        val arr = obj.optJSONArray("permissions")
        val list = mutableListOf<String>()
        if (arr != null) {
            for (i in 0 until arr.length()) {
                val p = arr.optString(i, "")
                if (p.isNotBlank()) list.add(p)
            }
        }
        mainHandler.post { permissionRequester(id, list) }
    }

    @JavascriptInterface
    fun openCamera(payloadJson: String) {
        val obj = parseJson(payloadJson) ?: return
        val id = obj.optString("id", UUID.randomUUID().toString())
        mainHandler.post { cameraStarter(id) }
    }

    @JavascriptInterface
    fun storageGet(payloadJson: String): String {
        val obj = parseJson(payloadJson) ?: return JSONObject().apply {
            put("ok", false); put("error", "bad_json")
        }.toString()
        val key = obj.optString("key", "")
        val id = obj.optString("id", "")
        val value = if (key.isBlank()) null else localStore.getString(key)
        return JSONObject().apply {
            put("ok", true)
            if (id.isNotBlank()) put("id", id)
            put("key", key)
            put("value", value)
            put("exists", value != null)
        }.toString()
    }

    @JavascriptInterface
    fun storageSet(payloadJson: String): String {
        val obj = parseJson(payloadJson) ?: return JSONObject().apply {
            put("ok", false); put("error", "bad_json")
        }.toString()
        val key = obj.optString("key", "")
        val value = if (obj.has("value") && !obj.isNull("value")) obj.optString("value") else null
        val id = obj.optString("id", "")
        if (key.isBlank()) {
            return JSONObject().apply {
                put("ok", false)
                if (id.isNotBlank()) put("id", id)
                put("error", "missing_key")
            }.toString()
        }
        if (value == null) localStore.remove(key) else localStore.putString(key, value)
        return JSONObject().apply {
            put("ok", true)
            if (id.isNotBlank()) put("id", id)
            put("key", key)
        }.toString()
    }

    @JavascriptInterface
    fun storageRemove(payloadJson: String): String {
        val obj = parseJson(payloadJson) ?: return JSONObject().apply {
            put("ok", false); put("error", "bad_json")
        }.toString()
        val key = obj.optString("key", "")
        val id = obj.optString("id", "")
        if (key.isBlank()) {
            return JSONObject().apply {
                put("ok", false)
                if (id.isNotBlank()) put("id", id)
                put("error", "missing_key")
            }.toString()
        }
        localStore.remove(key)
        return JSONObject().apply {
            put("ok", true)
            if (id.isNotBlank()) put("id", id)
            put("key", key)
        }.toString()
    }

    @JavascriptInterface
    fun requestPushPermission(payloadJson: String) {
        val obj = parseJson(payloadJson) ?: return
        val id = obj.optString("id", UUID.randomUUID().toString())
        mainHandler.post { pushPermissionRequester(id) }
    }

    @JavascriptInterface
    fun subscribePushToken(payloadJson: String) {
        val obj = parseJson(payloadJson) ?: return
        val id = obj.optString("id", UUID.randomUUID().toString())
        val enabled = obj.optBoolean("enabled", true)
        CoroutineScope(Dispatchers.IO).launch {
            val token = if (enabled) PushTokenProvider.getToken(activity) else null
            emit("nativePushToken", JSONObject().apply {
                put("id", id)
                put("ok", true)
                put("enabled", enabled)
                put("token", token ?: JSONObject.NULL)
            })
        }
    }

    fun emit(eventName: String, data: JSONObject) {
        val js = buildJsDispatch(eventName, data)
        mainHandler.post {
            try {
                webView.evaluateJavascript(js, null)
            } catch (_: Throwable) {
            }
        }
    }

    private fun buildJsDispatch(eventName: String, data: JSONObject): String {
        val eventEscaped = eventName.replace("\\", "\\\\").replace("'", "\\'")
        val json = data.toString().replace("\\", "\\\\").replace("'", "\\'")
        return "(function(){try{var e='$eventEscaped';var d=JSON.parse('$json');" +
            "if(window.HybridApp&&typeof window.HybridApp.onNativeEvent==='function'){window.HybridApp.onNativeEvent(e,d);}" +
            "else{window.dispatchEvent(new CustomEvent('native:'+e,{detail:d}));}" +
            "}catch(_){}})();"
    }

    private fun parseJson(payloadJson: String?): JSONObject? {
        if (payloadJson.isNullOrBlank()) return JSONObject()
        return try {
            JSONObject(payloadJson)
        } catch (_: JSONException) {
            null
        }
    }
}

class LocalStore(context: Context) {
    private val prefs = context.getSharedPreferences("hybrid_local_store", Context.MODE_PRIVATE)

    fun getString(key: String): String? = prefs.getString(key, null)

    fun putString(key: String, value: String) {
        prefs.edit().putString(key, value).apply()
    }

    fun remove(key: String) {
        prefs.edit().remove(key).apply()
    }
}

object PushTokenProvider {
    fun getToken(context: Context): String? {
        return try {
            val clazz = Class.forName("com.google.firebase.messaging.FirebaseMessaging")
            val getInstance = clazz.getMethod("getInstance")
            val instance = getInstance.invoke(null)
            val getToken = clazz.getMethod("getToken")
            val task = getToken.invoke(instance)
            val taskClass = Class.forName("com.google.android.gms.tasks.Task")
            val isComplete = taskClass.getMethod("isComplete").invoke(task) as Boolean
            if (!isComplete) {
                val awaitClass = Class.forName("com.google.android.gms.tasks.Tasks")
                val await = awaitClass.getMethod("await", taskClass)
                await.invoke(null, task)
            }
            val getResult = taskClass.getMethod("getResult")
            getResult.invoke(task) as? String
        } catch (_: Throwable) {
            null
        }
    }
}

fun createTempImageFile(context: Context): File {
    val dir = File(context.cacheDir, "camera").apply { mkdirs() }
    return File(dir, "img_${System.currentTimeMillis()}_${UUID.randomUUID()}.jpg")
}